#include <vector>
#include <algorithm>
#include <limits>

long long solve(std::vector<long long> nums, long long k) {
    int n = nums.size();
    if (n == 0) {
        return -1;
    }

    // 1. Calculate Prefix Maximums (PMax[i] = max(nums[0..i]))
    std::vector<long long> pmax(n);
    pmax[0] = nums[0];
    for (int i = 1; i < n; ++i) {
        pmax[i] = std::max(pmax[i - 1], nums[i]);
    }

    // 2. Calculate Suffix Minimums (SMin[i] = min(nums[i..n-1]))
    std::vector<long long> smin(n);
    smin[n - 1] = nums[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        smin[i] = std::min(smin[i + 1], nums[i]);
    }

    // 3. Iterate and check for the smallest stable index
    for (int i = 0; i < n; ++i) {
        // Unstable value U_i = PMax[i] - SMin[i]
        long long unstable_value = pmax[i] - smin[i];

        if (unstable_value <= k) {
            // Found the smallest stable index
            return i;
        }
    }

    // No stable index found
    return -1;
}

